import random
import math
from collections import deque
from dataclasses import dataclass, field
from typing import Any, Optional

@dataclass
class Experience:
    task_id: str
    input: Any
    output: Any
    reward: float = 0.0
    timestamp: int = 0

class ReservoirReplayBuffer:
    """
    Fixed-capacity buffer that maintains a uniform random sample of all
    experiences seen so far, regardless of arrival order (reservoir sampling).
    This prevents recency bias — early experiences have the same probability
    of being in the buffer as recent ones.
    """

    def __init__(self, capacity: int):
        self.capacity = capacity
        self.buffer: list[Experience] = []
        self._total_seen = 0

    def add(self, exp: Experience) -> None:
        self._total_seen += 1
        exp.timestamp = self._total_seen

        if len(self.buffer) < self.capacity:
            self.buffer.append(exp)
        else:
            # Replace a random position with probability capacity / total_seen
            j = random.randint(0, self._total_seen - 1)
            if j < self.capacity:
                self.buffer[j] = exp

    def sample(self, n: int) -> list[Experience]:
        n = min(n, len(self.buffer))
        return random.sample(self.buffer, n)

    def sample_by_task(self, task_id: str, n: int) -> list[Experience]:
        task_exps = [e for e in self.buffer if e.task_id == task_id]
        return random.sample(task_exps, min(n, len(task_exps)))

    def __len__(self) -> int:
        return len(self.buffer)


class PrioritisedReplayBuffer:
    """
    Replay buffer that samples high-priority (e.g. high-reward or high-loss)
    experiences more frequently. Uses a simple max-heap via sorted insertion.
    """

    def __init__(self, capacity: int, alpha: float = 0.6):
        self.capacity = capacity
        self.alpha = alpha           # priority exponent (0 = uniform, 1 = full priority)
        self.buffer: list[Experience] = []
        self.priorities: list[float] = []

    def add(self, exp: Experience, priority: Optional[float] = None) -> None:
        if priority is None:
            priority = max(self.priorities, default=1.0)  # new items get max priority
        if len(self.buffer) >= self.capacity:
            # Remove lowest priority item
            min_idx = self.priorities.index(min(self.priorities))
            self.buffer.pop(min_idx)
            self.priorities.pop(min_idx)
        self.buffer.append(exp)
        self.priorities.append(priority)

    def sample(self, n: int) -> list[Experience]:
        if not self.buffer:
            return []
        probs = [p ** self.alpha for p in self.priorities]
        total = sum(probs)
        probs = [p / total for p in probs]
        indices = random.choices(range(len(self.buffer)), weights=probs, k=min(n, len(self.buffer)))
        return [self.buffer[i] for i in indices]

    def update_priority(self, idx: int, priority: float) -> None:
        if 0 <= idx < len(self.priorities):
            self.priorities[idx] = priority

    def __len__(self) -> int:
        return len(self.buffer)


# Demo
if __name__ == "__main__":
    buf = ReservoirReplayBuffer(capacity=100)
    for i in range(500):
        buf.add(Experience(task_id="qa", input=f"q_{i}", output=f"a_{i}", reward=random.random()))

    samples = buf.sample(5)
    print(f"Buffer size: {len(buf)}")
    print(f"Sample timestamps: {[s.timestamp for s in samples]}")
    # Timestamps should be spread across 1-500, not clustered near 500
